<section class="auth-shell container"><div class="auth-card setup-card"><span class="eyebrow">First-time setup</span><h1>Create the owner account</h1><p>This page closes permanently after the first owner is created. Enter the one-time setup key from the private <code>.env</code> file.</p><?php if(!$setupReady): ?><div class="flash flash-error">Setup is locked until <code>APP_SETUP_TOKEN</code> contains a random secret of at least 32 characters.</div><?php endif; ?><form method="post" class="form-stack"><?= csrf_field() ?><label>One-time setup key<input type="password" name="setup_token" autocomplete="off" minlength="32" required></label><label>Owner name<input name="name" required maxlength="120"></label><label>Email<input type="email" name="email" required maxlength="254"></label><label>Phone<input type="tel" name="phone" maxlength="40"></label><label>Strong password <small>At least 12 characters</small><input type="password" name="password" minlength="12" maxlength="200" autocomplete="new-password" required></label><button class="button button-primary button-wide" type="submit" <?= $setupReady?'':'disabled' ?>>Create owner account<i data-lucide="shield-check"></i></button></form></div></section>
